import { waitUntil } from 'async-wait-until';
import './global.css';

let lastRawText = '';
let optionsExpanded = false;

function toggleOptions(): void {
  optionsExpanded = !optionsExpanded;
  document.getElementById('optionList')?.classList.toggle('show', optionsExpanded);
  document.getElementById('optionHeader')?.classList.toggle('open', optionsExpanded);
}

async function pickOption(text: string): Promise<void> {
  await executeSlashCommandsWithOptions(`/setinput ${text}`);
}

function renderOptions(opts: string[]): void {
  const optList = document.getElementById('optionList');
  if (!optList) return;
  optList.innerHTML = opts
    .map(
      (o) =>
        `<button class="option-btn" data-opt="${o.replace(/"/g, '&quot;')}">` +
        `<i class="fa-solid fa-circle-small"></i>${o}</button>`,
    )
    .join('');

  optList.querySelectorAll('.option-btn').forEach((btn) => {
    btn.addEventListener('click', function () {
      const opt = this.getAttribute('data-opt') || '';
      pickOption(opt);
    });
  });

  const countEl = document.getElementById('optionCount');
  if (countEl) countEl.textContent = opts.length ? `${opts.length} 个选项` : '';
  const headerEl = document.getElementById('optionHeader');
  if (headerEl) headerEl.style.display = opts.length ? 'flex' : 'none';
}

async function updateDisplay(): Promise<void> {
  const msgId = getCurrentMessageId();
  const msgs = getChatMessages(msgId);
  const rawText = msgs[0]?.message || '';
  if (rawText === lastRawText) return;
  lastRawText = rawText;

  // 正文
  const mainMatches = rawText.match(/<maintext>([\s\S]*?)<\/maintext>/g);
  const mainText = mainMatches
    ? mainMatches[mainMatches.length - 1].replace(/<\/?maintext>/g, '')
    : '';
  const mainBox = document.getElementById('mainBox');
  if (mainBox) {
    mainBox.innerHTML = mainText
      ? mainText
          .split('\n')
          .filter((l) => l.trim())
          .map((l) => `<p>${l}</p>`)
          .join('')
      : '';
  }

  // 选项
  const optMatches = rawText.match(/<option>([\s\S]*?)<\/option>/g);
  const opts = optMatches
    ? optMatches[optMatches.length - 1]
        .replace(/<\/?option>/g, '')
        .split('\n')
        .map((s) => s.trim())
        .filter((s) => s.length > 0)
    : [];
  renderOptions(opts);

  // 状态栏
  const vars = getVariables({ type: 'message' });
  const sd = _.get(vars, 'stat_data', {});
  const time = _.get(sd, '系统.当前时间', '--') || '--';
  const loc =
    (_.get(sd, '系统.当前位置', '') || '') + ' · ' + (_.get(sd, '系统.当前场景', '') || '');
  const jar = _.get(sd, '主角.精液罐余量', 0) || 0;
  const statBar = document.getElementById('statBar');
  if (statBar) {
    statBar.innerHTML =
      `<span class="stat-item stat-time"><i class="fa-regular fa-clock"></i> <span class="stat-val">${time}</span></span>` +
      `<span class="stat-divider">|</span>` +
      `<span class="stat-item"><i class="fa-solid fa-location-dot"></i> <span class="stat-val">${loc}</span></span>` +
      `<span class="stat-divider">|</span>` +
      `<span class="stat-item"><i class="fa-solid fa-flask"></i> <span class="stat-val">${jar}ml</span></span>`;
  }
}

$(async () => {
  await waitGlobalInitialized('Mvu');

  // Bind header click
  document.getElementById('optionHeader')?.addEventListener('click', toggleOptions);

  updateDisplay();
  setInterval(updateDisplay, 1000);
});
